from contextlib import contextmanager


@contextmanager
def managed_resource(log):
    # Everything before the yield is setup; the yielded value is what `as`
    # binds; everything after the yield is teardown. The try/finally guarantees
    # teardown runs whether the with-block finished normally or raised.
    log.append("open")
    resource = {"data": []}
    try:
        yield resource
    finally:
        log.append("close")

