import pytest

from solution import pop_keys


def test_removes_present_keys():
    data = {"a": 1, "b": 2, "c": 3}
    count = pop_keys(data, ["a", "c"])
    assert count == 2
    assert data == {"b": 2}


def test_missing_key_does_not_raise_and_is_not_counted():
    # Edge: a key that is absent is silently skipped and contributes 0.
    data = {"a": 1}
    count = pop_keys(data, ["a", "missing"])
    assert count == 1
    assert data == {}


def test_all_missing_returns_zero():
    data = {"a": 1}
    count = pop_keys(data, ["x", "y"])
    assert count == 0
    assert data == {"a": 1}


def test_empty_keys_removes_nothing():
    data = {"a": 1}
    assert pop_keys(data, []) == 0
    assert data == {"a": 1}


def test_suppress_skips_increment_on_missing():
    # Tricky: when KeyError is suppressed, the rest of that with-block (the
    # `removed += 1`) must NOT run. If the increment sat outside the with-block,
    # the count would wrongly include missing keys.
    data = {"a": 1, "b": 2}
    count = pop_keys(data, ["a", "nope", "b", "also_nope"])
    assert count == 2, "only successful deletions count; suppressed ones must not"
    assert data == {}


def test_unhashable_key_is_not_suppressed():
    # Tricky: only KeyError is listed in suppress. An unhashable key raises
    # TypeError, which must propagate rather than being silently ignored.
    data = {"a": 1}
    with pytest.raises(TypeError):
        pop_keys(data, [["unhashable"]])

import pytest

from solution import fetch_all


class Cursor:
    # A close()-able resource that is NOT itself a context manager.
    def __init__(self, rows):
        self.rows = list(rows)
        self.closed = False

    def __iter__(self):
        return iter(self.rows)

    def close(self):
        self.closed = True


class ExplodingCursor(Cursor):
    # Iterating this cursor raises partway through.
    def __iter__(self):
        def gen():
            yield self.rows[0]
            raise RuntimeError("connection dropped")
        return gen()


def test_returns_all_rows():
    cur = Cursor([1, 2, 3])
    assert fetch_all(cur) == [1, 2, 3]


def test_closes_cursor_on_normal_exit():
    cur = Cursor([1, 2])
    fetch_all(cur)
    assert cur.closed is True, "cursor must be closed after a normal read"


def test_empty_cursor():
    # Edge: no rows still closes cleanly.
    cur = Cursor([])
    assert fetch_all(cur) == []
    assert cur.closed is True


def test_closes_cursor_even_when_iteration_raises():
    # Tricky: the cursor must be closed even though iteration blew up halfway.
    # That is exactly what closing() guarantees via the with-block.
    cur = ExplodingCursor([10, 20, 30])
    with pytest.raises(RuntimeError):
        fetch_all(cur)
    assert cur.closed is True, "closing() must close the cursor even on error"
